import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Scanner;

public class SecurePathTraversal {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter file name:");
        String fileName = scanner.next();

        // Define a base directory to restrict access
        Path baseDir = Paths.get("C:\\path\\to\\directory\\");

        try {
            Path resolvedPath = baseDir.resolve(fileName).normalize();

            if (!resolvedPath.startsWith(baseDir)) {
                System.out.println("Invalid file path.");
                return;
            }

            byte[] fileContent = Files.readAllBytes(resolvedPath);
            String content = new String(fileContent);
            System.out.println("File content: " + content);
        } catch (Exception e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

